const cardFootsteps = [
  "right-36 top-6 h-7 w-7 -rotate-12",
  "right-28 top-16 h-6 w-6 rotate-6",
  "right-20 top-28 h-7 w-7 rotate-18",
];

export function DinoCardAccent({
  className = "",
  color = "#436485",
  flip = false,
  tone = "light",
}: {
  className?: string;
  color?: string;
  flip?: boolean;
  tone?: "light" | "dark";
}) {
  const footprintTone = tone === "dark" ? "text-white/15" : "text-[#5c84ad]/20";

  return (
    <div className={`pointer-events-none absolute inset-y-0 right-0 z-0 hidden w-56 overflow-hidden md:block ${className}`} aria-hidden>
      {cardFootsteps.map((position) => (
        <DinoFootprint key={position} className={`absolute ${position} ${footprintTone}`} />
      ))}
      <CuteDino
        className="absolute -bottom-6 right-2 h-32 w-32 opacity-[0.18]"
        color={color}
        flip={flip}
      />
    </div>
  );
}
